<template>
	<view>
		<view class="express-box">
			<u-cell-group :border="false">
				<u-cell-item :border-bottom="false" :arrow="true">
					<template #icon>
						<view class="icon-box"><u-icon name="map" /></view>
					</template>
					<template #title>
						<view class="detail" v-if="express.address">
							<view class="address-name">{{express.address}}</view>
							<view class="info">
								<text>{{express.real_name}}</text>
								<text>{{express.mobile}}</text>
							</view>
						</view>
						<view class="detail" v-else>
							<view class="address-name">暂无地址</view>
						</view>
					</template>
				</u-cell-item>
			</u-cell-group>
		</view>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			source: {
				type: Object,
				default: () => {}
			},
		},
		data() {
			return {
				express: {},
			};
		},
		computed: {

		},
		watch: {
			source: {
				handler(nv) {
					if (Object.keys(nv).length) {
						this.express = nv
					}
				},
				immediate: true,
			}
		},
		created() {

		},
		mounted() {

		},
		onHide() {

		},
		methods: {

		},
	};
</script>

