		background-color: #fff;
		border-radius: 10rpx;

		.icon-box {
			margin-right: 20rpx;
			font-size: 30rpx;

			::v-deep {
				.u-icon__icon {
					background-color: #FF504B;
					color: #fff;
					border-radius: 50%;
					padding: 10rpx;
				}
			}
		}

		.detail {
			display: flex;
			align-items: center;
