<template>
	<view style="width: 100%;">
		<u-form :model="form" ref="form" label-position="top" :error-type="['message']" :border-bottom="false">
			<u-form-item :label="value.cascaderLabel" prop="cascaderValues" :border-bottom="false">
				<!-- u-select 不支持多不确定深度的数据渲染，改用uni-data-picker组件替代 -->
				<!-- {{form}} -->
				<!-- {{data}} -->
				<uni-data-picker ref="picker" v-model="pickerValue" :localdata="data"
					:popup-title="`${value.cascaderLabel}`" :map="{text:'label',value:'_random'}" :hasSearch="true"
					@change="handelCascaderChange" />
			</u-form-item>
			<u-form-item v-for="item,index in list" :key="index" :label="item.name" :prop="item.key">
				<template v-if="item.type == 'text'">
					<u-input type="text" v-model="form[item.key]" :placeholder="item.tip" clearable />
				</template>
			</u-form-item>
		</u-form>
	</view>
</template>

<script>
	import {
		deepClone
	} from '@/common/fun.js'
	export default {
		props: {
			data: {
				type: Array,
				default: () => {
					return []
				}
			},
			value: {
				type: [Object, String],
				default: () => {
					return {
						cascaderLabel: '',
						cascaderValues: [],
						cascaderTexts: [],
						formValues: [],
					}
				}
			}
		},
		data() {
			return {
				pickerValue: '', // 最后一级的_random值。map属性定义了_random为唯一值
				form: {
					cascaderValues: [],
				},
				cascaderTexts: [],
				list: [],
			};
		},
		computed: {
			// 针对list的rule,cascader必填的
			rules() {
				let re = {
					// cascaderValues:{
					// 	required: true,
					// 	message: `${this.value.cascaderLabel}未选择`
					// }
				}
				if (this.list)
					this.list.forEach(item => {
						if (item.type == 'select') {
							re[item.key] = [{
								required: true,
								message: `${item.name}未选择`
							}]
						} else if (item.type == 'radio') {
							re[item.key] = [{
								required: true,
								message: `${item.name}未选择`
							}]
						} else if (item.type == 'cascader') {


						} else if (item.type == 'checkbox') {
							re[item.key] = [{
								required: true,
								validator: (rule, value, callback) => {
									if (Array.isArray(value) && value.length)
										callback()
									else
										callback(`${item.name}未选择`)
								}
							}]
						} else {
							if (item.vali) {
								if (item.vali == 'all') {
									re[item.key] = [{
										required: true,
										message: `${item.name}不能为空`,
									}]
								}
								if (item.vali == 'number')
									re[item.key] = [{
											required: true,
											message: `${item.name}不能为空`
										},
										{
											pattern: /^[0-9]*$/g,
											// 正则检验前先将值转为字符串
											transform(value) {
												return Number(value);
											},
											message: `${item.name}只能包含数字`
										}
									]
								else if (item.vali == 'qq') {
									re[item.key] = [{
											required: true,
											message: `${item.name}不能为空`
										},
										{
											regexp: /^[1-9][0-9]{4,10}$/,
											message: `${item.name}的格式不正确`
										}
									]
								} else if (item.vali == 'mobile') {
									re[item.key] = [{
											required: true,
											message: `${item.name}不能为空`
										},
										{
											regexp: /^1\d{10}$/,
											message: `${item.name}的格式不正确`
										}
									]
								} else if (item.vali == 'email') {
									re[item.key] = [{
											required: true,
											message: `${item.name}不能为空`
										},
										{
											type: 'email',
											message: `${item.name}的格式不正确`
										}
									]
								} else if (item.vali == 'url') {
									re[item.key] = [{
											required: true,
											message: `${item.name}不能为空`
										},
										{
											type: 'url',
											message: `${item.name}的格式不正确`
										}
									]
								}
							}
						}
					})
				return re
			}
		},
		watch: {
			form: {
				handler(nv) {
					const copy = deepClone(nv)
					let obj = {}
					obj.cascaderValues = copy.cascaderValues
					obj.cascaderTexts = this.cascaderTexts

					delete copy.cascaderValues
					let arr = []
					for (let i in copy) {
						let find = this.list.find(item => item.key == i)
						arr.push({
							key: i,
							value: copy[i],
							name: find.name
						})
					}
					obj.formValues = arr

					obj.cascaderLabel = this.value.cascaderLabel
					console.log(obj)
					this.$emit('input', obj)
				},
				deep: true
			}
		},
		mounted() {
			// console.log(this.data)
			const {
				cascaderValues,
				cascaderTexts
			} = this.value
			this.$set(this.form, 'cascaderValues', cascaderValues)

			if (cascaderValues.length) {
				this.pickerValue = cascaderValues[cascaderValues.length - 1]
				// this.initNodeForm()
			}
			this.cascaderTexts = [...cascaderTexts]
		},
		methods: {
			handelCascaderChange(e) {
				const value = e.detail.value

				let value_arr = value.map(item => item.value)
				let text_arr = value.map(item => item.text)

				this.form.cascaderValues = [...value_arr]
				this.cascaderTexts = [...text_arr]

				this.initNodeForm()
			},
			// 初始化cascader节点的表单
			initNodeForm() {
				let node_data = this.findItemById(this.data, this.pickerValue)

				if (node_data) {
					if (node_data.list && Array.isArray(node_data.list)) {
						this.list = deepClone(node_data.list)
						// 因为是动态表单，所以要清理form中的键，注意一定要保留cascaderValues
						for (let i in this.form) {
							if (i != 'cascaderValues') {
								delete this.form[i]
							}
						}
						this.value.formValues.map(item => {
							this.$set(this.form, item.key, item.value)
						})
					} else {
						// this.$refs['form'].resetFields()
						// 清理form中的键，注意一定要保留cascaderValues
						for (let i in this.form) {
							if (i != 'cascaderValues') {
								delete this.form[i]
							}
						}
						this.list = []
					}
				} else {
					// this.$refs['form'].resetFields()
					// 清理form中的键，注意一定要保留cascaderValues
					for (let i in this.form) {
						if (i != 'cascaderValues') {
							delete this.form[i]
						}
					}
					this.list = []
				}
			},
			findItemById(list, _random) {
				// 每次进来使用find遍历一次
				let res = list.find((item) => item._random == _random)

				if (res) {
					return res
				} else {
					for (let i = 0; i < list.length; i++) {
						if (list[i].children instanceof Array && list[i].children.length > 0) {
							res = this.findItemById(list[i].children, _random)

							if (res) return res
						}
					}

					return null
				}
			},
			clearValidate(key) {
				this.$refs['form'].clearValidate(key)
			},
			doValid() {
				this.$refs['form'].setRules(this.rules)
				return new Promise((resolve, reject) => {
					this.$refs['form'].validate((valid) => {
						if (valid) {
							resolve()
						} else {
							reject()
						}
					})
				})
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.uni-data-pickerview {
			margin-bottom: 118rpx;
		}

		.check {
			margin-top: 20rpx;
		}
	}
</style>