<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" :z-index="12" :custom-style="customStyle"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true" @close="close"
			@open="open">
			<view class="popup-title">
				<text>地址选择</text>
				<view @click="handelManage" class="btn manage-btn">管理</view>
			</view>
			<view class="popup-content">
				<scroll-view @touchmove.stop scroll-y class="scroll_content" :style="{height:'600rpx'}">
					<u-cell-group>
						<u-cell-item v-for="(item,index) in list" :key="index" :class="{on:item.id ==activeId}"
							@click="activeId =item.id">
							<template #title>
								<view class="address-content">
									<view class="top">
										<text class="name">{{item.real_name}}</text>
										<text class="mobile">{{item.mobile}}</text>
										<text class="default-tag" v-if="item.is_default">默认</text>
									</view>
									<view class="bottom">
										{{item.address}},{{item.area}},{{item.city}},{{item.street}}
									</view>
								</view>
							</template>
						</u-cell-item>
					</u-cell-group>
				</scroll-view>
			</view>
			<view class="popup-footer">
				<view class="btn ok-btn" @click="handelOk">确 定</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			customStyle: {
				type: Object,
				default: () => {}
			}
		},
		data() {
			return {
				popupShow: false,
				list: [],
				total: 0,

				activeId: 0,
			};
		},
		computed: {

		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			show({
				id
			}) {
				this.activeId = id
				this.popupShow = true
			},
			close() {
				this.activeId = 0
			},
			async open() {
				const {
					list,
					total
				} = await this.$u.api.getMemberAddressList()
				this.list = list
				this.total = total
			},
			handelManage() {
				this.popupShow = false
				this.$util.on('/pages/ucenter_sub/express/index')
			},
			handelOk() {
				this.popupShow = false

				const find = this.list.find(item => item.id == this.activeId)
				this.$emit('ok', find)
			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.on {
		background-color: #f4f4f5 !important;

		::v-deep {
			.u-cell {
				background-color: #f4f4f5 !important;
			}
		}
	}

	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
		position: relative;

		.manage-btn {
			position: absolute;
			left: 10rpx;
			top: 5rpx;
			color: #fa3534;
			padding: 0;
		}
	}

	.popup-content {
		padding: 20rpx;
		min-height: 600rpx;

		.address-content {
			display: flex;
			flex-direction: column;
			line-height: 1;
			gap: 20rpx;

			.top {
				.name {
					color: #333;
					font-weight: bolder;
				}

				.mobile {
					margin-left: 20rpx;
				}

				.default-tag {
					background-color: #fa3534;
					color: #fff;
					padding: 2rpx 6rpx;
					font-size: 22rpx;
					border-radius: 6rpx;
					line-height: 1;
					margin-left: 20rpx;
				}
			}
		}
	}

	.popup-footer {
		padding: 40rpx;

		.ok-btn {
			width: 100%;
			padding: 20rpx;
			background-image: linear-gradient(90deg, #FE8A56, #FF504B);
			border-radius: 40rpx;
		}
	}
</style>