<template>
	<view style="">
		<view class="goods-box">
			<view class="goods-item" v-for="item,index in goodsList" :key="index">
				<view class="merchant">
					<view class="merchant-name">
						<u-image width="40rpx" border-radius="10rpx" height="40rpx" :src="item.logo"></u-image>
						<text>{{item.name}}</text>
						<u-icon name="arrow-right" color="#B0B0B0" size="20"></u-icon>
					</view>
				</view>
				<view class="goods-list-box">
					<view class="goods-list-item" v-for="item2,index2 in item.list" :key="index2">
						<view class="img">
							<template v-if="item2.goods.goods_type == 3 && item2.goods.spec_type == 1">
								<u-image width="150rpx" height="150rpx" border-radius="10rpx"
									:src="item2.attr.goods_img" @click="() => {
										$util.on(`/pages/goods/detail?id=${item2.goods_id}&spec_id=${item2.goods_sku_id}`)
									}"></u-image>
							</template>
							<template v-else>
								<u-image width="150rpx" height="150rpx" border-radius="10rpx"
									:src="item2.goods.goods_img" @click="() => {
									$util.on(`/pages/goods/detail?id=${item2.goods.id}`)
								}"></u-image>
							</template>
						</view>
						<view class="info">
							<view class="goods-name">
								<text class="name line2">{{item2.goods.goods_name}}</text>
							</view>
							<view class="spec" v-if="item2.goods.goods_type == 3 && item2.goods.spec_type == 1"
								@click="handelSpecClick(item2)">
								<text>{{item2.attr.suk}}</text>
								<u-icon name="arrow-right" color="#969799" size="20"></u-icon>
							</view>
							<view class="spec" v-else-if="item2.goods.goods_type == 1 || item2.goods.goods_type == 2"
								@click="handelAttachClick(item2)">
								<text>修改订单参数</text>
								<u-icon name="arrow-right" color="#969799" size="20"></u-icon>
							</view>
							<view class="tag">
								<!-- <text>7天无理由退货</text> -->
							</view>
							<view class="price">
								<text>¥</text>
								<text
									v-if="item2.goods.goods_type == 3 && item2.goods.spec_type == 1">{{item2.attr.goods_price}}</text>
								<text v-else>{{item2.goods.goods_price}}</text>
							</view>
						</view>
						<view class="quantity">
							<slot name='quantity' :row="item2" :idx="index2"></slot>
						</view>
					</view>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			goodsList: {
				type: Array,
				default: () => []
			},
		},
		data() {
			return {

			};
		},
		computed: {

		},
		watch: {
			quantity(nv) {
				this.quantityValue = nv
			},
		},
		created() {

		},
		mounted() {

		},
		methods: {
			// 规格被点击
			handelSpecClick({
				id,
				goods,
				attr
			}) {
				this.$emit('spec-choose', {
					id,
					goods_id: goods.id,
					spec_id: attr.id
				})
			},
			// 显示弹框修改下单模板
			handelAttachClick({
				id,
				goods
			}) {
				this.$emit('ordertpl-choose', {
					id,
					goods_id: goods.id
				})
			},
			handelRemark() {
				this.$emit('remark-click')
			},
			// 获取商品库存
			getStockNum(row, field) {
				return row.goods[field]
				// if(row.goods.goods_type == 3 && row.goods.spec_type == 1)
				// {
				// 	return row.attr[field]
				// }
				// else
				// {
				// 	return row.goods[field]
				// }
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.goods-box {
		display: flex;
		flex-direction: column;
		gap: 20rpx;

		.goods-item {
			display: flex;
			flex-direction: column;
			gap: 20rpx;
			background-color: #fff;
			border-radius: 10rpx;
			padding: 20rpx;

			.merchant {
				display: flex;
				gap: 20rpx;

				.merchant-name {
					display: flex;
					align-items: center;
					gap: 20rpx;
				}
			}

			.goods-list-box {
				display: flex;
				flex-direction: column;
				gap: 20rpx;

				.goods-list-item {
					display: flex;
					gap: 20rpx;
					align-items: center;

					.img {
						width: 150rpx;
					}

					.info {
						flex: 1;

						.goods-name {
							display: flex;
							gap: 20rpx;
							align-items: center;

							.name {
								flex: 1;
							}
						}

						.spec {
							color: #B0B0B0;
						}

						.tag {
							display: flex;
							gap: 10rpx;
							margin-top: 10rpx;

							&>text {
								border: 1px solid #F74B20;
								border-radius: 10rpx;
								font-size: 80%;
								color: #F74B20;
								padding: 1rpx 4rpx;
							}
						}

						.price {
							color: #FD5406;

							&>text:nth-child(1) {
								font-size: 20rpx;
								margin-right: 10rpx;
							}

							&>text:nth-child(2) {
								font-size: 40rpx;
								font-weight: bold;
							}
						}
					}

					.quantity {
						align-self: flex-start;
					}
				}
			}
		}
	}
</style>