<template>
	<view>
		<u-popup v-model="detailshow" mode="bottom" :z-index="999" :custom-style="{}"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true"
			@close="close">
			<view class="popup-title">订单备注</view>
			<view class="popup-content">
				<view class="wrap">
					<u-field v-model="content" :field-style="{}" :border-bottom="false" type="textarea"
						@input="handelInput" placeholder="请输入订单备注" label-width="0" :fixed="true" maxlength="200" />
				</view>
			</view>
			<view class="popup-footer">
				<u-button type="warning" shape="circle" @click="handelOk">确 定</u-button>
			</view>
		</u-popup>
	</view>
</template>

<script>
	import {
		debounce
	} from '@/common/fun.js'
	export default {
		components: {},
		props: {
			popupShow: {
				type: Boolean,
				default: false
			},
			remark: {
				type: String,
				default: () => {}
			},
		},
		data() {
			return {
				detailshow: false,
				content: '',
				customStyle: {
					marginTop: '20px', // 注意驼峰命名，并且值必须用引号包括，因为这是对象
					color: '#F74B20'
				},
			}
		},
		watch: {
			popupShow: {
				handler(nv) {
					this.detailshow = this.popupShow
				},
			},
			remark(nv) {
				this.content = nv
			},
		},
		methods: {
			handelInput: debounce(function(e) {
				console.log(e)
			}, 500),
			close() {
				this.$emit('update:popupShow', false)
			},
			handelOk(){
				this.$emit('ok',this.content)
				this.close()
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
	}

	.popup-content {
		padding: 20rpx;
		height: 600rpx;

		.wrap {
			background-color: #f4f4f5;
			height: 300rpx;
			overflow-y: auto;
		}
	}

	.popup-footer {
		padding: 40rpx;
	}
</style>