<template>
	<view class="freight-box">
		<u-cell-group :border="false">
			<u-cell-item title="商品总价" :value="`¥ ${source.total_price}`" :border-bottom="false" :arrow="false"
				hover-class="none" />
			<u-cell-item title="配送运费" :value="postageText" :border-bottom="false" :arrow="false" hover-class="none"
				:value-style="{color:'red','font-weight':'bolder'}" />
			<u-cell-item v-if="source.coupon_price && source.coupon_price>0" title="优惠券优惠" :value="`¥ ${source.coupon_price}`" :border-bottom="false"
				:arrow="false" hover-class="none" :value-style="{color:'red','font-weight':'bolder'}" />
				<u-cell-item v-if="source.promotions_price && source.promotions_price>0" title="满减优惠" :value="`¥ ${source.promotions_price}`" :border-bottom="false"
				:arrow="false" hover-class="none" :value-style="{color:'red','font-weight':'bolder'}" />
		
		</u-cell-group>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			source: {
				type: Object,
				default: () => {}
			},
		},
		computed: {
			postageText() {
				if (this.source.postage)
					return `¥ ${this.source.postage}`
				else
					return `包邮`
			}
		},
	}
</script>

<style scoped lang="scss" scoped>
	.freight-box {
		background-color: #fff;
		border-radius: 10rpx;
	}
</style>