<template>
	<view class="page">
		<u-navbar title="确认订单" :custom-back="$util.back" :border-bottom="false"></u-navbar>
		<scroll-view @touchmove.stop scroll-y class="scroll_content" :style="{height:scrollHeight+'px'}">
			<view class="box">
				<Address :source="address" @click.native="chooseAddress" />
			</view>
			<view class="box">
				<Goods :goodsList="goodsList" @remark-click="handelRemarkClick" @spec-choose="handelSpecChoose"
					@ordertpl-choose="handelOrderTplChoose">
					<template v-slot:quantity="{row,idx}">
						<goods-num :quantity="row.num" :num-type="row.goods.num_type"
							:start-count="row.goods.start_count" :end-count="row.goods.end_count"
							:num-count="row.goods.num_count" @quantity-change="handelQuantityChange(row,$event)" />
					</template>
				</Goods>
			</view>
			<view class="box">
				<goods-freight :source="freightData" />
			</view>
		</scroll-view>
		<view class="footer">
			<view class="wrap">
				<view class="submit-btn" @click="$u.throttle(doSubmit, 500)">提交订单</view>
			</view>
		</view>
		<Remark :popupShow.sync="showRemark" :remark="orderForm.mark" @ok="handelRemarkOk" />
		<spec-choose ref="spec-choose" @ok="handelSpecChange" />
		<ordertpl-choose ref="ordertpl-choose" @ok="handelOrderTplChange" />
		<choose-address-popup ref="choose-address-popup" @ok="handelAddressChange" />
	</view>
</template>

<script>
	import Address from './components/address/'
	import Goods from './components/goods/'
	import Remark from './components/remark-popup'
	import ChooseGoodsSpecDialog from '@/components/ChooseGoodsSpecDialog/'
	import ChooseOrderTplDialog from '@/components/ChooseOrderTplDialog/'
	import GoodsNum from './components/goods/goods-num'
	import GoodsFreight from './components/goods/freight'
	import ChooseAddressPopup from '@/components/ChooseAddressPopup'
	import {
		mapGetters
	} from 'vuex'
	import _ from 'lodash'

	export default {
		components: {
			Address,
			Goods,
			Remark,
			'spec-choose': ChooseGoodsSpecDialog,
			'ordertpl-choose': ChooseOrderTplDialog,
			'goods-num': GoodsNum,
			'goods-freight': GoodsFreight,
			'choose-address-popup': ChooseAddressPopup
		},
		data() {
			return {
				sys: this.$util.sys(),
				scrollHeight: 0,

				// 第一步立即购买
				queryForm: {
					goods_id: '', //商品ID
					// batch_tpl: '', //(手工订单需要)批量下单模板json
					quantity: 0, //下单数量
					// mark: '', //订单备注
					// pay_type: '', //支付方式(填写则直接返回支付信息,不填则返回支付订单号) alipay=支付宝,wechat=微信支付,qqpay=QQ支付,balance=余额
					// is_check: 0, //创建前检查1=检查,0=创建订单
					goods_spec_id: '', //商品规格ID
					cart_batch_tpl: '', //购物车下单ID逗号隔开
				},

				buyType: 1, //1商品购买，2购物车购买,很重要！！！
				goodsList: [],

				// 创建订单
				orderForm: {
					goods_id: '',
					batch_tpl: '',
					quantity: 0,
					mark: '',
					goods_spec_id: '',
					address_id: '',
					cart_batch_tpl: '',
				},

				showRemark: false,

				address: {}, //收货地址数据
				priceGroup: {
					postage: 0, // 运费
					total_price: 0, // 订单总价
					coupon_price: 0, // 优惠券金额
					promotions_price: 0 // 满减优惠
				},
				orderKey: ''
			}
		},
		computed: {
			...mapGetters(['deviceInfo']),
			freightData() {
				return {
					total_price: this.priceGroup.total_price,
					postage: this.priceGroup.postage,
					coupon_price: this.priceGroup.coupon_price,
					promotions_price: this.priceGroup.promotions_price,
				}
			},
		},
		onUnload() {

		},
		onReady() {
			this.$nextTick(() => {
				const {
					windowHeight,
					statusBarHeight
				} = uni.getSystemInfoSync()
				uni.createSelectorQuery().in(this).select(".scroll_content").boundingClientRect(res => {
					this.scrollHeight = windowHeight - res.top - uni.upx2px(110)
				}).exec()
			})
		},
		onShow() {
			const {
				id,
				spec_id,
				quantity,
				cart_ids, // 购物车ids,逗号分割
			} = this.$Route.query
			this.queryForm.goods_id = id
			this.queryForm.goods_spec_id = spec_id
			this.queryForm.cart_batch_tpl = cart_ids
			this.queryForm.quantity = quantity - 0 || 1
			if (cart_ids) {
				this.buyType = 2
			} else {
				this.buyType = 1
				this.orderForm.goods_spec_id = spec_id
				this.orderForm.quantity = quantity - 0 || 1
			}


			if (!id && !cart_ids) {
				uni.showToast({
					icon: 'none',
					title: '商品id不存在'
				})
				setTimeout(() => {
					this.$util.back()
				}, 500)
				return
			}
			this.fetchData()
		},
		onLoad(e) {

		},
		methods: {
			async fetchData() {
				try {
					const {
						goods,
						merchant,
						cartInfo,
						order,
						address,
						orderKey,
						priceGroup
					} = await this.$u.api.confirm(this.queryForm)
					this.order = order
					this.address = address || {}
					this.orderKey = orderKey
					this.priceGroup = priceGroup

					this.orderForm.address_id = address.id
					if (this.buyType == 1) {
						this.goodsList = [{
							...merchant,
							list: [{
								num: this.orderForm.quantity,
								goods,
								attr: goods.spec_value
							}]
						}]
						this.orderForm.goods_id = goods.id
						this.orderForm.batch_tpl = ""
					} else {
						this.goodsList = cartInfo
						this.orderForm.cart_batch_tpl = this.getCartBatchTpl()
					}
				} catch (e) {
					// this.$util.back()
				}
			},
			getCartBatchTpl() {
				let arr = []
				this.goodsList.forEach(item => {
					item.list.map(item2 => {
						// let tmp = {
						// 	cart_id: '',
						// 	batch_tpl: []
						// }
						// tmp.cart_id = item2.id

						arr.push(item2.id)
					})
				})
				return arr
			},
			chooseAddress() {
				if (_.isEmpty(this.address)) {
					this.$Router.push({
						path: '/pages/ucenter_sub/express/add'
					})
				} else {
					this.$refs['choose-address-popup'].show({
						id: this.orderForm.address_id
					})
				}
			},
			// 收货地址回调
			async handelAddressChange(e) {
				this.orderForm.address_id = e.id
				this.address = e
				const re = await this.$u.api.priceGroup({
					address_id: e.id,
					orderKey: this.orderKey
				})
				this.priceGroup = re
			},
			// 数量改变回调
			async handelQuantityChange(row, num) {
				row.num = num
				if (this.buyType == 1) {
					this.orderForm.quantity = num
				} else if (this.buyType == 2) {
					this.$u.api.goodsCartNum({
						id: row.id,
						num
					})
				}
			},
			// 监听订单备注点击
			handelRemarkClick() {
				this.showRemark = !this.showRemark
			},
			// 订单备注保存回调
			handelRemarkOk(e) {
				this.orderForm.mark = e
			},
			// 显示规格选择
			handelSpecChoose(e) {
				this.$refs['spec-choose'].show(e)
			},
			// 选择规格回调
			async handelSpecChange(e) {
				if (this.buyType == 1) {
					this.goodsList[0].list[0].attr = e.specValue
					this.orderForm.goods_spec_id = e.editForm.goods_sku_id
				} else if (this.buyType == 2) {
					await this.$u.api.goodsCartSave(e.editForm)
					this.fetchData()
				}
			},
			// 显示下单模板
			handelOrderTplChoose(e) {
				this.$refs['ordertpl-choose'].showEdit(e)
			},
			// 选择下单模板回调
			async handelOrderTplChange({
				id,
				goods_id,
				batch_tpl,
				mark
			}) {
				if (this.buyType == 1) {
					this.orderForm.batch_tpl = JSON.stringify(batch_tpl)
				} else if (this.buyType == 2) {
					await this.$u.api.goodsCartSave({
						id,
						goods_id,
						batch_tpl: JSON.stringify(batch_tpl),
						mark
					})
					this.fetchData()
				}

			},
			// 提交订单
			async doSubmit() {
				const {
					order_sn
				} = await this.$u.api.createOrder(this.orderForm)

				// window._agl && window._agl.push(['track', ['success', {t: 6}]])
				this.$util.on(`/pages/goods/buy?ordersn=${order_sn}`)
			},
		}
	}
</script>


<style lang="scss" scoped scoped>
	.scroll_content {
		padding-top: 20rpx;
	}

	.box {
		padding: 0 20rpx 20rpx 20rpx;
	}

	.footer {
		position: fixed;
		bottom: 0;
		bottom: constant(safe-area-inset-bottom);
		bottom: env(safe-area-inset-bottom);
		z-index: 11;
		width: 100%;
		height: 104rpx;
		background-color: #fff;
		flex-wrap: nowrap;
		justify-content: space-between;
		align-items: center;
		display: flex;
		padding: 20rpx;

		.wrap {
			width: 100%;

			.submit-btn {
				background-image: linear-gradient(90deg, #FE8A56, #FF504B);
				border-radius: 40rpx;
				width: 100%;
				text-align: center;
				line-height: 80rpx;
				color: #fff;
			}
		}
	}


	::v-deep {

		.uni-fab__circle--rightBottom,
		.uni-fab--rightBottom {
			z-index: 1;
			margin-bottom: 60rpx;
		}
	}
</style>